import { chromium } from 'playwright';
import fs from 'fs';

const URL = 'https://ivxholding.com';
const viewports = [
  { name: 'mobile', width: 390, height: 844 },
  { name: 'tablet', width: 768, height: 1024 },
  { name: 'desktop', width: 1280, height: 800 },
];

const results = [];
const browser = await chromium.launch({ headless: true });

for (const vp of viewports) {
  const context = await browser.newContext({ viewport: { width: vp.width, height: vp.height } });
  const page = await context.newPage();
  const consoleErrors = [];
  const failedRequests = [];

  page.on('console', msg => {
    if (msg.type() === 'error') consoleErrors.push({ type: msg.type(), text: msg.text() });
  });
  page.on('pageerror', err => consoleErrors.push({ type: 'pageerror', text: err.message }));
  page.on('requestfailed', req => failedRequests.push({ url: req.url(), failure: req.failure()?.errorText || 'unknown' }));

  try {
    await page.goto(URL, { waitUntil: 'networkidle', timeout: 30000 });
    await page.waitForTimeout(2000);

    // Scroll to bottom to check for layout shifts
    await page.evaluate(() => window.scrollTo(0, document.body.scrollHeight));
    await page.waitForTimeout(500);

    const finalUrl = page.url();
    const title = await page.title();
    const height = await page.evaluate(() => document.body.scrollHeight);

    // Screenshot
    await page.screenshot({ path: `/tmp/landing-${vp.name}.png`, fullPage: false });

    results.push({
      viewport: vp.name,
      width: vp.width,
      height: vp.height,
      finalUrl,
      title,
      scrollHeight: height,
      consoleErrors: consoleErrors.length,
      failedRequests: failedRequests.length,
      consoleErrorDetails: consoleErrors.slice(0, 10),
      failedRequestDetails: failedRequests.slice(0, 10),
      status: 'OK'
    });
  } catch (err) {
    results.push({ viewport: vp.name, width: vp.width, height: vp.height, status: 'ERROR', error: err.message });
  }
  await context.close();
}

await browser.close();

fs.writeFileSync('/tmp/landing-responsive-results.json', JSON.stringify(results, null, 2));
console.log(JSON.stringify(results, null, 2));
EOF

